 SYSCTL_VNET_INT(_net_inet6_ip6, IPV6CTL_ACCEPT_RTADV, accept_rtadv,
        CTLFLAG_RW, &VNET_NAME(ip6_accept_rtadv), 0,
        "Default value of per-interface flag for accepting ICMPv6 Router"

