multicast? */
-
 /* New entries should be added here from current IPV6CTL_MAXID value. */
 /* to define items, should talk with KAME guys first, for *BSD compatibility */
 #define IPV6CTL_STEALTH                45
@@ -619,6 +618,9 @@ struct ip6_mtuinfo {
